import java.io.*;

public class SecureDeserializationExample {

    private static final String ALLOWED_CLASS = "com.example.MyClass"; // Define the allowed class for deserialization

    public static void main(String[] args) {
        String userInput = "userInput.ser"; // Assume this is user-provided input

        try (FileInputStream fis = new FileInputStream(userInput);
             ObjectInputStream ois = new ObjectInputStream(fis)) {

            Object obj = ois.readObject();

            if (obj.getClass().getName().equals(ALLOWED_CLASS)) {
                System.out.println("Deserialized object: " + obj);
            } else {
                System.out.println("Invalid object type");
            }

        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Insecure Deserialization
